#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int l = N, r = -1;
        bool sorted = true;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x != i+1) {
                sorted = false;
                if (i < l) l = i;
                if (i > r) r = i;
            }
        }
        if (sorted) {
            printf("0\n");
        } else if (r - l + 1 <= K) {
            printf("1\n");
        } else {
            printf("2\n");
        }
    }
    return 0;
}

