#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        l = N; r = -1; sorted_flag = True
        for i in range(N):
            x = int(next(it))
            if x != i+1:
                sorted_flag = False
                if i < l: l = i
                if i > r: r = i
        if sorted_flag:
            out_lines.append('0')
        elif r - l + 1 <= K:
            out_lines.append('1')
        else:
            out_lines.append('2')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

